67: // NewTableReaderImpl creates a new table reader Implementation.
68: func NewTableReaderImpl(reader *plannercore.PhysicalTableReader, source *logicalop.DataSource) *TableReaderImpl {
69: 	base := baseImpl{plan: reader}
70: 	impl := &TableReaderImpl{
71: 		baseImpl:    base,
72: 		tblInfo:     source.TableInfo,
73: 		tblColHists: source.TblColHists,
74: 	}
75: 	return impl
76: }
77: 
78: // CalcCost calculates the cost of the table reader Implementation.
79: func (impl *TableReaderImpl) CalcCost(outCount float64, children ...memo.Implementation) float64 {
80: 	reader := impl.plan.(*plannercore.PhysicalTableReader)
81: 	width := cardinality.GetAvgRowSize(impl.plan.SCtx(), impl.tblColHists, reader.Schema().Columns, false, false)
82: 	sessVars := reader.SCtx().GetSessionVars()
83: 	// TableReaderImpl don't have tableInfo property, so using nil to replace it.
84: 	// Todo add the tableInfo property for the TableReaderImpl.
85: 	networkCost := outCount * sessVars.GetNetworkFactor(impl.tblInfo) * width
86: 	// copTasks are run in parallel, to make the estimated cost closer to execution time, we amortize
87: 	// the cost to cop iterator workers. According to `CopClient::Send`, the concurrency
88: 	// is Min(DistSQLScanConcurrency, numRegionsInvolvedInScan), since we cannot infer
89: 	// the number of regions involved, we simply use DistSQLScanConcurrency.
90: 	copIterWorkers := float64(sessVars.DistSQLScanConcurrency())
91: 	impl.cost = (networkCost + children[0].GetCost()) / copIterWorkers
92: 	return impl.cost
93: }
94: 
95: // GetCostLimit implements Implementation interface.
96: func (impl *TableReaderImpl) GetCostLimit(costLimit float64, _ ...memo.Implementation) float64 {
97: 	reader := impl.plan.(*plannercore.PhysicalTableReader)
98: 	sessVars := reader.SCtx().GetSessionVars()
99: 	copIterWorkers := float64(sessVars.DistSQLScanConcurrency())
100: 	if math.MaxFloat64/copIterWorkers < costLimit {
101: 		return math.MaxFloat64
102: 	}
